function t(key) {
  return (translations[currentLang] && translations[currentLang][key])
    || translations.en[key]
    || key;
}

function applyTranslations() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    el.textContent = t(key);
  });
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    const key = el.getAttribute('data-i18n-html');
    el.innerHTML = t(key);
  });
  // Update select options
  document.querySelectorAll('[data-i18n-option]').forEach(el => {
    const key = el.getAttribute('data-i18n-option');
    el.textContent = t(key);
  });
  // Update HTML lang attribute
  document.documentElement.lang = currentLang;
}

function setLanguage(lang) {
  currentLang = lang;
  localStorage.setItem('jaketz-lang', lang);

  // Update the selector display
  const display = document.getElementById('langDisplay');
  if (display) {
    const labels = { en: '🇺🇸 EN', pt: '🇧🇷 PT', es: '🇪🇸 ES' };
    display.textContent = labels[lang] || labels.en;
  }

  applyTranslations();

  // Re-render dynamic content
  if (typeof renderSkeletons === 'function') {
    renderSkeletons();
    renderListings(getFilteredListings());
  }
  if (typeof renderSpecialEvents === 'function') {
    renderSpecialEvents();
  }
}
